{"code": "# Load the LGG clinical data
import json
import re
from collections import Counter
from math import log10

# Get LGG patients data
clinical_result = var_functions.execute_python:60
if isinstance(clinical_result, str) and clinical_result.endswith('.json'):
    with open(clinical_result, 'r') as f:
        clinical_data = json.load(f)
else:
    clinical_data = clinical_result

# Create mapping of barcodes to histology
lgg_patients = {}
for p in clinical_data['patients']:
    lgg_patients[p['barcode']] = p['histology']

print(f"LGG patients: {len(lgg_patients)}")
print("Histology distribution:", dict(Counter(lgg_patients.values())))

# Load IGF2 expression data
igf2_result = var_functions.query_db:64
if isinstance(igf2_result, str) and igf2_result.endswith('.json'):
    with open(igf2_result, 'r') as f:
        igf2_data = json.load(f)
else:
    igf2_data = igf2_result

print(f"Total IGF2 records: {len(igf2_data)}")

# Filter for LGG patients and collect expression by histology
histology_expressions = {}
matched_patients = set()

for record in igf2_data:
    barcode = record['ParticipantBarcode']
    if barcode in lgg_patients:
        hist_type = lgg_patients[barcode]
        # Only include valid histology (not in brackets)
        if not (hist_type.startswith('[') and hist_type.endswith(']')):
            if hist_type not in histology_expressions:
                histology_expressions[hist_type] = []
            # Compute log10-transformed expression (normalized_count + 1)
            expr = float(record['normalized_count']) + 1
            log_expr = log10(expr)
            histology_expressions[hist_type].append(log_expr)
            matched_patients.add(barcode)

print(f"Matched patients: {len(matched_patients)}")
print("Expressions per histology:")
for hist, exprs in histology_expressions.items():
    print(f"  {hist}: {len(exprs)} samples")

# Compute averages
averages = {}
for hist, exprs in sorted(histology_expressions.items()):
    if exprs:  # Only compute if we have data
        avg = sum(exprs) / len(exprs)
        averages[hist] = avg
        print(f"{hist}: {avg:.4f}")

result = {
    'total_lgg_patients': len(lgg_patients),
    'matched_with_expression': len(matched_patients),
    'averages': {k: round(v, 4) for k, v in averages.items()}
}

print('__RESULT__:')
print(json.dumps(result))"}

